  allocation_id = aws_eip.nat_gw_staging_eip.id
  subnet_id     = "subnet-0a1b2c3d"

  tags = {
    Name        = "nat-gw-staging-app"
    Environment = "staging"
    FinOpsAction = "DESTROY"
    FinOpsReviewed = "true"
