  lifecycle {
    prevent_destroy = false
  }
}

resource "aws_eip" "nat_gw_staging_eip" {
  domain = "vpc"

  tags = {
    Name        = "nat-gw-staging-eip"
    Environment = "staging"
    FinOpsAction = "DESTROY"
    FinOpsReviewed = "true"
  }

  lifecycle {
    prevent_destroy = false
  }
}
